import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { ApiService } from './api.service';
import { PagedResult } from '../models/common.models';
import {
  CourseListDto, CourseDetailDto, CourseFilterDto, CourseHomePage, CourseEnrollmentDto,
  CreateCourseDto, UpdateCourseDto,
  ModuleSummaryDto, CreateModuleDto, UpdateModuleDto,
  ModuleItemDto, CreateModuleItemDto, UpdateModuleItemDto,
  CoursePageSummaryDto, CoursePageDto, CreateCoursePageDto, UpdateCoursePageDto
} from '../models/course.models';

@Injectable({ providedIn: 'root' })
export class CourseService {
  constructor(private api: ApiService) {}

  // ── Courses ────────────────────────────────────────────────────────────────
  getAll(filter?: CourseFilterDto): Observable<PagedResult<CourseListDto>> {
    return this.api.getPaged<CourseListDto>('courses', filter as any);
  }

  getById(id: number): Observable<CourseDetailDto> {
    return this.api.get<CourseDetailDto>(`courses/${id}`);
  }

  create(dto: CreateCourseDto): Observable<CourseDetailDto> {
    return this.api.post<CourseDetailDto>('courses', dto);
  }

  update(id: number, dto: UpdateCourseDto): Observable<CourseDetailDto> {
    return this.api.put<CourseDetailDto>(`courses/${id}`, dto);
  }

  publish(id: number): Observable<void> {
    return this.api.patch<void>(`courses/${id}/publish`);
  }

  unpublish(id: number): Observable<void> {
    return this.api.patch<void>(`courses/${id}/unpublish`);
  }

  archive(id: number): Observable<void> {
    return this.api.patch<void>(`courses/${id}/archive`);
  }

  setHomePage(id: number, value: CourseHomePage): Observable<CourseDetailDto> {
    return this.api.patch<CourseDetailDto>(`courses/${id}/home-page?value=${value}`);
  }

  delete(id: number): Observable<void> {
    return this.api.delete(`courses/${id}`);
  }

  // ── Course enrollments (per-course) ────────────────────────────────────────
  enrollUser(courseId: number, userId: number): Observable<void> {
    return this.api.post<void>(`courses/${courseId}/enroll/${userId}`, {});
  }

  unenrollUser(courseId: number, userId: number): Observable<void> {
    return this.api.delete(`courses/${courseId}/enroll/${userId}`);
  }

  getEnrollments(courseId: number): Observable<CourseEnrollmentDto[]> {
    return this.api.get<CourseEnrollmentDto[]>(`courses/${courseId}/enrollments`);
  }

  enrollMany(courseId: number, userIds: number[]): Observable<number> {
    return this.api.post<number>(`courses/${courseId}/enrollments`, userIds);
  }

  getUserEnrolledCourses(userId: number): Observable<CourseListDto[]> {
    return this.api.get<CourseListDto[]>(`courses/user/${userId}/enrolled`);
  }

  // ── Modules ────────────────────────────────────────────────────────────────
  createModule(dto: CreateModuleDto): Observable<ModuleSummaryDto> {
    return this.api.post<ModuleSummaryDto>('modules', dto);
  }

  updateModule(id: number, dto: UpdateModuleDto): Observable<ModuleSummaryDto> {
    return this.api.put<ModuleSummaryDto>(`modules/${id}`, dto);
  }

  deleteModule(id: number): Observable<void> {
    return this.api.delete(`modules/${id}`);
  }

  reorderModules(courseId: number, orderedIds: number[]): Observable<void> {
    return this.api.patch<void>(`modules/reorder?courseId=${courseId}`, orderedIds);
  }

  setModulePublished(moduleId: number, value: boolean): Observable<ModuleSummaryDto> {
    return this.api.patch<ModuleSummaryDto>(`modules/${moduleId}/published?value=${value}`);
  }

  // ── Module items (Canvas-style ModuleItem) ─────────────────────────────────
  getModuleItem(id: number): Observable<ModuleItemDto> {
    return this.api.get<ModuleItemDto>(`moduleitems/${id}`);
  }

  createModuleItem(dto: CreateModuleItemDto): Observable<ModuleItemDto> {
    return this.api.post<ModuleItemDto>('moduleitems', dto);
  }

  updateModuleItem(id: number, dto: UpdateModuleItemDto): Observable<ModuleItemDto> {
    return this.api.put<ModuleItemDto>(`moduleitems/${id}`, dto);
  }

  deleteModuleItem(id: number): Observable<void> {
    return this.api.delete(`moduleitems/${id}`);
  }

  setModuleItemPublished(id: number, value: boolean): Observable<ModuleItemDto> {
    return this.api.patch<ModuleItemDto>(`moduleitems/${id}/published?value=${value}`);
  }

  reorderModuleItems(moduleId: number, orderedIds: number[]): Observable<void> {
    return this.api.patch<void>(`moduleitems/reorder?moduleId=${moduleId}`, orderedIds);
  }

  markModuleItemComplete(id: number, timeSpentMinutes = 0): Observable<void> {
    return this.api.post<void>(`moduleitems/${id}/complete?timeSpentMinutes=${timeSpentMinutes}`, {});
  }

  // ── Pages ──────────────────────────────────────────────────────────────────
  getPages(courseId: number): Observable<CoursePageSummaryDto[]> {
    return this.api.get<CoursePageSummaryDto[]>(`pages/course/${courseId}`);
  }

  getPage(id: number): Observable<CoursePageDto> {
    return this.api.get<CoursePageDto>(`pages/${id}`);
  }

  createPage(dto: CreateCoursePageDto): Observable<CoursePageDto> {
    return this.api.post<CoursePageDto>('pages', dto);
  }

  updatePage(id: number, dto: UpdateCoursePageDto): Observable<CoursePageDto> {
    return this.api.put<CoursePageDto>(`pages/${id}`, dto);
  }

  setPagePublished(id: number, value: boolean): Observable<CoursePageDto> {
    return this.api.patch<CoursePageDto>(`pages/${id}/published?value=${value}`);
  }

  setPageAsFrontPage(id: number): Observable<void> {
    return this.api.patch<void>(`pages/${id}/front-page`);
  }

  deletePage(id: number): Observable<void> {
    return this.api.delete(`pages/${id}`);
  }
}
